import{_ as e,o as a,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"38. On Call","description":"","frontmatter":{"title":"38. On Call","eba":"Doctors in Training 2022-2026","topics":["hours","rosters","on-call","allowances"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/38-on-call.md","filePath":"ebas/doctors-in-training/hours-of-work/38-on-call.md"}'),r={name:"ebas/doctors-in-training/hours-of-work/38-on-call.md"};function s(l,o,i,c,p,d){return a(),t("div",null,[...o[0]||(o[0]=[n('<h1 id="_38-on-call" tabindex="-1">38. On Call <a class="header-anchor" href="#_38-on-call" aria-label="Permalink to &quot;38. On Call&quot;">​</a></h1><p><strong>38.1</strong> On-call must be identified in the roster including whether it is General On-call at subclause 38.2(a) or Standby On-all at subclause 38.2(b). The provisions of this clause 38 are to be read in conjunction with <a href="/eba/ebas/doctors-in-training/hours-of-work/40-telephone-calls-to-doctors-outside-of-working-hours.html">clause 40</a> (Telephone Calls to Doctors Outside of Working Hours), clause 39 (Recall) and <a href="/eba/ebas/doctors-in-training/allowances/54-telephone-allowance.html">clause 54</a> (Telephone Allowance).</p><p><strong>38.2</strong> Types of On-call</p><p><strong>(a)</strong> General On-call</p><p><strong>(i)</strong> General on-call means an on-call period where the Doctor is rostered to hold themselves available to:</p><p>A. undertake remote recall; that is, provide clinical advice without a return to the workplace (such as by telephone or computer); and/or</p><p>B. be recalled to their usual place of work.</p><p><strong>(b)</strong> Standby On-call</p><p><strong>(i)</strong> Standby on-call means an on-call period where the Doctor is rostered to hold themselves available to be on-call solely for the purpose of returning to the Health Service (for which payment will be made in accordance with <a href="/eba/ebas/doctors-in-training/hours-of-work/39-recall-return-to-workplace.html">clause 39</a>) in circumstances such as replacing unplanned absences or to address clinical need and does not provide any advice by telephone.</p><p><strong>(ii)</strong> Notwithstanding any other term in this clause, the period of standby on- call should be no longer than the specific shift it is designed to cover.</p><p><strong>38.3</strong> On-call Allowance</p><p>A Doctor rostered on-call -must be paid the on-call Allowance pursuant to <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, Table 2.2(b) which has been calculated on the following basis:</p><p><strong>(a)</strong> 2.5% of the Doctor’s ordinary weekly rate of pay; or</p><p><strong>(b)</strong> on a public holiday pursuant to <a href="/eba/ebas/doctors-in-training/leave/63-public-holidays.html">clause 63</a> (Public Holidays), 3.5% of the Doctor&#39;s ordinary weekly rate of pay.</p><p><strong>38.4</strong> Limitations</p><p><strong>(a)</strong> For the purposes of calculating payment, each period of on-call must not exceed 16 hours.</p><p><strong>(b)</strong> Where a Doctor is rostered to perform six times 16 hour periods of on-call within six consecutive days, that Doctor must be released from on-call duty for 24 hours paid or unpaid as according to the roster or projected roster.</p><p><strong>(c)</strong> The on-call payment does not apply to Doctors who receive payment on a percentage of fees generated basis for out of hours work when on a General Practice Training Program Rotation pursuant to <a href="/eba/ebas/doctors-in-training/doctor-employment/31-rotation-to-a-general-practice-training-program.html">clause 31</a> (Rotation to a General Practice Training Program).</p><p>Plain language terms: on call.</p>',19)])])}const g=e(r,[["render",s]]);export{u as __pageData,g as default};
